const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
});

rl.on('line', (line) => {
  try {
    // Split the line by delimiter based on the first occurrence of a comma, tab, or semicolon
    const [header, ...data] = line.split(/,\s*|\t\s*|\S+/); 

    // Handle quoted fields with embedded commas
    if (header.includes(',"') && header.includes('"')) {
      header = header.replace(/,"([^"]+)","/, ',"$1"');
    }

    const parsedData = data.map((row) => {
      let result = {};
      // Split the row by comma, tab, or semicolon 
      const [key, value] = row.split(/,\s*|\t\s*|\S+/);
      result[key] = value;

      return result;
    });

    // Convert parsed data to JSON string and send it to stdout
    const jsonResult = JSON.stringify(parsedData, null, 2)
    console.log(jsonResult); 
  } catch (error) {
    console.error(`Error parsing line: ${line}`);
    console.error(error);
  }
});

rl.on('close', () => {
  console.log('Script finished.');
});
```


